#include <stdio.h>
#include <string.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        static char N[10000005];
        scanf("%s", N);
        int freq[10] = {0};
        for (int i = 0; N[i]; ++i) {
            freq[N[i] - '0']++;
        }
        for (int code = 65; code <= 90; ++code) {
            int a = code / 10;
            int b = code % 10;
            if (a != b) {
                if (freq[a] && freq[b]) putchar((char)code);
            } else {
                if (freq[a] >= 2) putchar((char)code);
            }
        }
        putchar('\n');
    }
    return 0;
}

