import sys

def solve():
    data = sys.stdin.read().split()
    if not data:
        return
    t = int(data[0])
    idx = 1
    out_lines = []
    for _ in range(t):
        N = data[idx]; idx += 1
        freq = [0]*10
        for ch in N:
            freq[ord(ch)-48] += 1
        res = []
        for code in range(65, 91):
            a = code // 10
            b = code % 10
            if a != b:
                if freq[a] and freq[b]:
                    res.append(chr(code))
            else:
                if freq[a] >= 2:
                    res.append(chr(code))
        out_lines.append(''.join(res))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

