const input = fs.readFileSync(0, 'utf-8').trim().split(/\s+/);
let pos = 0;
const T = parseInt(input[pos++], 10);
let output = [];
for (let tc = 0; tc < T; tc++) {
  const N = input[pos++];
  const freq = new Array(10).fill(0);
  for (let i = 0; i < N.length; i++) {
    freq[N.charCodeAt(i) - 48]++;
  }
  let line = '';
  for (let code = 65; code <= 90; code++) {
    const a = Math.floor(code / 10);
    const b = code % 10;
    if (a !== b) {
      if (freq[a] && freq[b]) line += String.fromCharCode(code);
    } else {
      if (freq[a] >= 2) line += String.fromCharCode(code);
    }
  }
  output.push(line);
}
